INSERT INTO public.photos VALUES (24440, 'Mercado de Zaragoza 1896', 'Joaqu├¡n Pallar├®s: Mercado de Zaragoza, ├│leo sobre tela. Representaci├│n de la antigua plaza del Mercado de Zaragoza, posiblemente la zona de los puestos cercanos a la calle de la Torre Nueva, a la derecha. A├▒os despu├®s, con la construcci├│n del gran y modernista Nuevo Mercado, este entorno ser├¡a radicalmente transformado. Este cuadro fue expuesto en 1896 en la "Tercera Exposici├│n de Bellas Artes e Industrias Art├¡sticas de Barcelona" donde recibi├│ uno de los primeros premios y fue adquirido para una colecci├│n particular por 2.500 pesetas. En la actualidad est├í expuesto en el Museo Nacional de Arte de Catalu├▒a,', 1896, 1896, 1896, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65600600, -0.88280600, '0101000020E61000006CCD565EF23FECBF69FD2D01F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14895521993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14895521993.webp', 'https://www.flickr.com/photos/zaragozaantigua/14895521993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24443, 'Calle de Predicadores 1965', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Setiembre 1965. "Fotos de fachadas y portales." Imagen de la calle Predicadores 6, 8 y 10, inmuebles luego derribados. En la planta calle del n├║mero 10, un comercio de aperos y artilugios propios de la primera revoluci├│n neol├¡tica, lo que es todo un elogio: a├║n no hab├¡an sido superados. Dos pisos por arriba, una criatura a la que le han echado la persiana.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65705500, -0.88295100, '0101000020E61000004E0E9F742241ECBF2E56D4601AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15049552929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15049552929.webp', 'https://www.flickr.com/photos/zaragozaantigua/15049552929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24453, 'Calle Manifestaci├│n 1974', 'Foto Antonio Herranz 1974. D├¡a de lluvia de 1974, visto desde la cafeter├¡a Lanuza, en la esquina de la plaza del mismo nombre con la calle Manifestaci├│n de Zaragoza. Justo enfrente, calle Salduba, con su churrer├¡a a la izquierda. Tanto la cafeter├¡a como la churrer├¡a, extintas. Fuente: www.facebook.com/photo.php?fbid=380357982121037&set=o...', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST├ôRICO', 41.65651100, -0.88203600, '0101000020E610000006A1BC8FA339ECBF6D3B6D8D08D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15832794146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15832794146.webp', 'https://www.flickr.com/photos/zaragozaantigua/15832794146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24663, 'Calle Antonio P├®rez 1889', 'J. L├®vy et Cie, 1889 Calle de Antonio P├®rez, hoy avenida C├®sar Augusto. Torre├│n de la Zuda.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65702100, -0.88186800, '0101000020E610000019726C3D4338ECBF82E49D4319D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14991359335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14991359335.webp', 'https://www.flickr.com/photos/zaragozaantigua/14991359335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24668, 'Murallas romanas 1987', 'Foto Rogelio Allepuz. Vista de las murallas romanas de Zaragoza, con la iglesia de San Juan de los Panetes y su torre en restauraci├│n, al fondo. En primer plano, so├▒ador poblador. Fuente: www.facebook.com/photo.php?fbid=428574137238890&set=p...', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST├ôRICO', 41.65705700, -0.88202900, '0101000020E610000066F4A3E19439ECBFCF4D9B711AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15824921956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15824921956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15824921956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24678, 'Calle Prudencio 1977', 'Imagen de la calle de Prudencio, con vista parcial de los vestigios edilicios de la derecha, apenas ya el lienzo de la planta calle, que se corresponden con el tramo entre los antiguos n├║meros 23 y 33 de la manzana delimitada por las calles Danzas, Convertidos, Prudencio, y la Virgen, esta ├║ltima, al fondo. Sobre estos solares, al principio de la d├®cada de los a├▒os 90 se realiz├│ una importante ampliaci├│n de los Juzgados de la plaza del Pilar. En uno de los portales de la imagen quedan vestigios de un antiguo despacho, posiblemente, de "carb├│n mineral y vegetal". Fuente visual: amable aportaci├│n personal de Pablo Vald├®s.', 1977, 1977, 1977, 'Anos 70', 'CASCO HIST├ôRICO', 41.65621000, -0.88079300, '0101000020E61000009B7631CD742FECBF72A774B0FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26557500921.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26557500921.webp', 'https://www.flickr.com/photos/zaragozaantigua/26557500921/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24682, 'Pl. de San Antonio Abad 1925', 'Imagen capturada durante la ceremonial entrada en la ciudad del nuevo arzobispo, Rigoberto Dom├®nech Valls, sobre preceptiva y albina caballer├¡a. La oficial comitiva, de la que forman parte las primeras autoridades municipales, transita por el arranque de la calle de la Manifestaci├│n, a la altura de la antigua plaza de San Antonio Abad, espacio ocupado durante siglos por el convento de San Antonio Abad, o San Ant├│n, desde donde se pod├¡a acceder al antiguo palacio de la Castellan├¡a de Amposta, y a la iglesia de San Juan de los Panetes. Fuente visual: colecci├│n Francisco G├│rriz, en AMZ.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST├ôRICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33732221366.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33732221366.webp', 'https://www.flickr.com/photos/zaragozaantigua/33732221366/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24684, 'Avenida C├®sar Augusto 2012', 'Foto: Oliver Duch. Vista en marzo de 2012 de la avenida de C├®sar Augusto durante las obras de la segunda fase de la l├¡nea 1 del tranv├¡a. A la izquierda, iglesia de San Juan de los Panetes y murallas romanas. Al fondo, torres del Pilar. A la derecha, estatua de C├®sar Augusto y "Alegor├¡a de la Puerta de la Paz" (1989-2013). Fuente: Heraldo de Arag├│n.', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65693400, -0.88220000, '0101000020E610000097FF907EFB3AECBFB3D0CE6916D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39763283425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39763283425.webp', 'https://www.flickr.com/photos/zaragozaantigua/39763283425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24690, 'Plaza del Pilar 1990', 'Imagen de las obras de rehabilitaci├│n y embellecimiento de la plaza del Pilar que capturada durante la construcci├│n del aparcamiento de los Juzgados. Preside la escena el "Monumento a los h├®roes y m├írtires de Zaragoza ca├¡dos en la Cruzada de Liberaci├│n 1936-1939" terminado en 1954, que luego ser├¡a desmantelado y trasladado al cementerio cat├│lico de Torrero. Tras ├®l, la iglesia de San Juan de los Panetes, el Torre├│n de la Zuda y el todav├¡a despejado inmueble del n┬║ 90 del paseo de Echegaray y Caballero.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65709800, -0.88065500, '0101000020E610000058E20165532EECBF2D228AC91BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50458786302.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50458786302.webp', 'https://www.flickr.com/photos/zaragozaantigua/50458786302/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24691, 'Puerta de la Paz 1990', 'Imagen capturada en el entorno de la "Alegor├¡a de la Puerta de la Paz" que, a la izquierda, fue instalada en 1989 donde estuviera la desaparecida Puerta de Toledo, tras la instalaci├│n en 1990 de la semoviente estatua de C├®sar Augusto. Centra la escena el Torre├│n de la Zuda, la iglesia de San Juan de los Panetes y un tramo del antiguo recinto amurallado de piedra de la ciudad. A la izquierda, la avenida de C├®sar Augusto y el puente de Santiago.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65685700, -0.88230700, '0101000020E61000001805C1E3DB3BECBF0893E2E313D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50462117802.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50462117802.webp', 'https://www.flickr.com/photos/zaragozaantigua/50462117802/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24909, 'Av. C├®sar Augusto 1990', 'Colocaci├│n de la estatua de C├®sar Augusto junto al Mercado Central de Zaragoza en 1990. Fuente: dp-foto.blogspot.com', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST├ôRICO', 41.65684100, -0.88225300, '0101000020E61000004C88B9A46A3BECBF02D6AA5D13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20517141058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20517141058.webp', 'https://www.flickr.com/photos/zaragozaantigua/20517141058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24916, 'C├®sar Augusto 1999', 'Despu├®s de tres meses ausente de su emplazamiento, la estatua de C├®sar Augusto vuelve al conjunto monumental cercano al tramo de las Murallas Romanas junto al Mercado Central, donde se ubica desde 1990. Hab├¡a estado en M├®rida para hacerle una copia. Fuente: Agencia EFE.', 1999, 1999, 1999, 'Anos 90', 'CASCO HIST├ôRICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24335602140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24335602140.webp', 'https://www.flickr.com/photos/zaragozaantigua/24335602140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24921, 'Murallas Romanas 1960', 'Estatua de C├®sar Augusto en su pedestal con columnas laterales ad hoc, colocada junto a las murallas romanas entre 1950 y 1966, procedente de la plaza de Para├¡so. Hacia 1980 ser├í trasladada de nuevo a su ubicaci├│n original, donde permanecer├í hasta 1990, que volver├í a las inmediaciones de las murallas. A la derecha, Torre├│n de la Zuda. Fuente: Heraldo de Arag├│n.', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65707100, -0.88185800, '0101000020E610000036E9B6442E38ECBF34130CE71AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32850130890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32850130890.webp', 'https://www.flickr.com/photos/zaragozaantigua/32850130890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24925, 'Calle de las Murallas 1962', 'Imagen capturada en la calle de las Murallas y centrada en la estatua del romano C├®sar Augusto y un tramo de la muralla de piedra de la ciudad. Al fondo, la calle Imperial y los antiguos edificios de vivienda que flanqueaban el principio de la calle de Aben Aire. Fuente visual: FOTOTECA-BCN, en www.todocoleccion.net', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST├ôRICO', 41.65707100, -0.88185800, '0101000020E610000036E9B6442E38ECBF34130CE71AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39027931225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39027931225.webp', 'https://www.flickr.com/photos/zaragozaantigua/39027931225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25104, 'Caballero cadete, 1957', 'Imagen de su alteza real el caballero cadete Juan Carlos de Borb├│n y Borb├│n capturada en la plaza del Pilar durante una revista militar. Entre 1955 y 1957 Juan Carlos form├│ parte de la XIV promoci├│n de la Academia General Militar, de la que sali├│ con el grado de alf├®rez de infanter├¡a. Al fondo, gran solar resultante del derribo de la manzana entre las calles de la Regla y de Prudencio, cuyo tramo hasta la calle de la Virgen queda, por ello, visible desde la plaza. A la derecha y fuera de plano, el Altar de la Patria o Monumento a los h├®roes y m├írtires de Zaragoza ca├¡dos en la Cruzada de Liberaci├│n 1936-1939.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST├ôRICO', 41.65693000, -0.88048300, '0101000020E610000011E335AFEA2CECBF72E1404816D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50894093206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50894093206.webp', 'https://www.flickr.com/photos/zaragozaantigua/50894093206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25383, 'Los ├║ltimos momentos de Lanuza 1591', 'Los ├║ltimos momentos de Lanuza, ├│leo sobre lienzo, Eduardo L├│pez del Plano, Diputaci├│n de Zaragoza, 1864. Juan de Lanuza, Justicia de Arag├│n, va a ser decapitado por orden de Felipe II en la plaza del Mercado de Zaragoza. A la derecha, la C├írcel de la Manifestaci├│n y la Puerta de Toledo, derruidas en 1848. Al fondo, el Torre├│n de la Zuda. Fuente: web.dpz.es/arscatalogi.es/', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15255817173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15255817173.webp', 'https://www.flickr.com/photos/zaragozaantigua/15255817173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25384, 'Pl. del Justicia 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 08/04/1966. La monumental fachada de la barroca iglesia de Santa Isabel de Portugal, o San Cayetano, es excepcional por su riqueza y profusi├│n decorativa. Las airosas torres delimitan una estructura vignolesca enmascarada por recargada ornamentaci├│n y decoraci├│n abigarrada, de estilo churrigueresco, ├║nica en la ciudad. Alcanza efectos crom├íticos ins├│litos mediante la combinaci├│n de materiales como piedra negra para los elementos arquitect├│nicos, piedra ocre para los decorativos, y alabastro blanco para el fondo. El escudo her├íldico de Arag├│n preside la entrada, flanqueada por las estatuas, a la izquierda la de San Andr├®s Avelino (de los Cl├®rigos Regulares o teatinos) y a la derecha la de San Cayetano (fundador de los Cl├®rigos Regulares Teatinos). En la hornacina superior est├í la titular de la iglesia (Santa Isabel de Portugal), representada con el manto entreabierto para dejar asomar unas rosas. En la imagen, nocturna vista de la fachada de la iglesia, desde la plaza del Justicia. Como es abril, hay se├▒ores y ni├▒os disfrazados en medio.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65584700, -0.88185100, '0101000020E6100000973C9E961F38ECBF011764CBF2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15278515585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15278515585.webp', 'https://www.flickr.com/photos/zaragozaantigua/15278515585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25385, 'Puerta de Toledo c.1840', '"Desfile jocoso con novillos", l├ípiz y acuarela sobre papel, an├│nimo, Museo de Zaragoza. Festejo popular con novillos cabalgados por actores disfrazados en la plaza del Mercado. Al fondo a la izquierda, la puerta de San Ildefonso y el Torre├│n de la Zuda. A la derecha, las ruinas de la Puerta de Toledo, ordenada derribar en 1842. Fuente visual: El coso de la Misericordia de Zaragoza (2014).', 1840, 1840, 1840, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65651100, -0.88203600, '0101000020E610000006A1BC8FA339ECBF6D3B6D8D08D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15457827898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15457827898.webp', 'https://www.flickr.com/photos/zaragozaantigua/15457827898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25387, 'Personal Jesus 1965', 'Archivo Municipal. Gerardo Sancho Ramo. 1965. "Procesiones de Semana Santa". "Your own, personal Jesus, someone to hear your prayers, someone who cares. Your own, personal Jesus, someone to hear your prayers, someone who''s there." "Personal Jesus", Depeche Mode (Violator, 1990). Penitente descalzo con mono de faena en funciones propias del Nazareno, iniciando calvario tras salir de la iglesia de Santa Isabel (derecha), en la plaza del Justicia. La calle del fondo es Santa Isabel. Va camino de Manifestaci├│n. Mujeres expectantes.', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST├ôRICO', 41.65589500, -0.88147000, '0101000020E6100000BEF6CC920035ECBF124E0B5EF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15898684026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15898684026.webp', 'https://www.flickr.com/photos/zaragozaantigua/15898684026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25391, 'Puerta de la Paz 2012', 'En 1989 se construy├│ este conjunto, denominado "Alegor├¡a de la Puerta de la Paz", obra de Juan Mart├¡n Trenor, en el lugar donde se ubicaba la Puerta de Toledo. Fue derribado en 2013, en el marco de las obras de la l├¡nea 1 del nuevo tranv├¡a. La estatua de C├®sar Augusto permanece. Fuente: www.fotonazos.es/2012/01/alegoria-de-la-puerta-de-la-paz-...', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65661600, -0.88220000, '0101000020E610000097FF907EFB3AECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18459101003.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18459101003.webp', 'https://www.flickr.com/photos/zaragozaantigua/18459101003/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25394, 'Pl. de Lanuza 1967', 'Esquina de la plaza de Lanuza con la calle de Predicadores (derecha). Fuente visual: Foto Leonardo P├®rez Obis, donada por ├üngel Hern├índez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65680000, -0.88264000, '0101000020E6100000AD86C43D963EECBFA301BC0512D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22777943419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22777943419.webp', 'https://www.flickr.com/photos/zaragozaantigua/22777943419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25397, 'Murallas Romanas 1964', 'De buena ma├▒ana, un marzo que "marzeaba" lo normal, y sin cierzo, Gerardo Sancho ascendi├│ al Torre├│n de la Zuda, a verlas pasar (las im├ígenes), y en el momento preciso, captur├│ esta, que con el tiempo se ha convertido en una visual est├índar. Centra la toma el recreado pa├▒o de las defensas romanas donde se levantara la antigua puerta este de la ciudad, luego Bab Qala''ath, luego de Toledo. A la izquierda, el it├ílico y semoviente C├®sar Augusto, en uno de sus sitiales provisionales, presidiendo una plaza en su imperial honor, y en construcci├│n. Al fondo, el Mercado Central, a├║n eclipsado por los restos decimon├│nicos de los adosados al gran complejo hospitalario de San Juan. A la derecha, los n├║meros impares de la antigua calle de la Triper├¡a, luego de Antonio P├®rez, luego Imperial, luego V├¡a Imperial, y en unos a├▒os, parte de una nueva avenida de C├®sar Augusto, actual denominaci├│n de esas "de toda la vida". Hac├¡a un par de a├▒os que el Ministerio de Obras P├║blicas hab├¡a aprobado levantar un inmediato y nuevo puente para circulaci├│n motorizada sobre el Ebro, y sus cimientos ya estaban asentados. Poco tiempo despu├®s, las manzanas de la imagen, entre las calles Predicadores, Aben Aire, y Escobar, ser├¡a retranqueadas unos metros para fluidificar el tr├ínsito rodado hasta la puerta del Carmen. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST├ôRICO', 41.65674400, -0.88225400, '0101000020E6100000637C98BD6C3BECBF10ECF82F10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24397219414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24397219414.webp', 'https://www.flickr.com/photos/zaragozaantigua/24397219414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25398, 'Pl. de Lanuza 1960', 'Foto: Jos├® Antonio Duce. Vista de la entrada lateral del Mercado Central desde los porches de la plaza de Lanuza, a la altura de Casa Gav├¡n. Fuente: www.gozazaragoza.com/', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST├ôRICO', 41.65607900, -0.88276900, '0101000020E610000023861DC6A43FECBFD34B8C65FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24430625962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24430625962.webp', 'https://www.flickr.com/photos/zaragozaantigua/24430625962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25399, 'C├®sar Augusto 2013', 'Foto: Oliver Duch. Instant├ínea tomada el 12 de marzo de 2013, durante las obras de demolici├│n de los arcos instalados en 1989 con el nombre de "Alegor├¡a de la Puerta de la Paz". Frente a ellos, la estatua de C├®sar Augusto. Sobre ├®l, la viga superior de uno de los arcos. Fuente: Heraldo de Arag├│n.', 2013, 2013, 2013, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65687000, -0.88229600, '0101000020E61000001E882CD2C43BECBF9CDCEF5014D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29908956287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29908956287.webp', 'https://www.flickr.com/photos/zaragozaantigua/29908956287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25401, 'Plaza de Lanuza 1966', 'Imagen capturada durante una procesi├│n, posiblemente, de la cofrad├¡a de la Instituci├│n de la Sagrada Familia, en la antigua plaza de Lanuza. Al fondo, la calle Manifestaci├│n y la plaza del Justicia (derecha). A la izquierda, los ├║ltimos restos edilicios adosados al tramo de las murallas de piedra de San Juan de los Panetes; entre ellos se encontraba el n┬║ 27 de la plaza de Lanuza, donde figuraba la hospeder├¡a Caroll y San Jorge. A la derecha, el esquinero edificio en cuyos bajos estaba el caf├® Lanuza. En su fachada, publicidad comercial de los productos l├ícteos "Massanes y Grau", buscando aumentar cuota de mercado tras la entrada de capital suizo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST├ôRICO', 41.65660000, -0.88201800, '0101000020E61000006C770FD07D39ECBFDC4603780BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31072174660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31072174660.webp', 'https://www.flickr.com/photos/zaragozaantigua/31072174660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25402, 'VIsta a├®rea Mercado c.1968', 'Vista a├®rea parcial del centro hist├│rico de Zaragoza. Arriba, el r├¡o Ebro. A la izquierda, el barrio de San Pablo y el Mercado Central. En el centro, la iglesia de Santa Isabel. Abajo, la sombra de la torre de San Felipe se proyecta donde se levantaba la Torre Nueva. Fuente visual: foto Pedro Marco.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65581200, -0.88197600, '0101000020E6100000B16B7BBB2539ECBF8429CAA5F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32855076964.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32855076964.webp', 'https://www.flickr.com/photos/zaragozaantigua/32855076964/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20971, 'Juslibol y Alfocea 1858', '"Croquis del monte y dehesa que posee el pueblo de Juslibol, empalmando con el terreno que litiga como Pardina de Miranda y sus lim├¡trofes". Firmado por Eusebio Blasco y Taula, Ge├│metra y Director de Caminos Vecinales. Archivo Hist├│rico Provincial de Zaragoza, 1858. Plano orientado con el Norte abajo, que incluye los actuales barrios rurales de Juslibol (a la izquierda) y Alfocea (en el centro).', 1858, 1858, 1858, 'Siglo XIX', NULL, 41.69364300, -0.89998100, '0101000020E61000001DAF40F4A4CCECBFB70C384BC9D84440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19300278255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19300278255.webp', 'https://www.flickr.com/photos/zaragozaantigua/19300278255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25404, 'Pl. del Justicia 1967', 'Imagen centrada en la gran fachada clasicista de la casa del siglo XVII de la familia Cavero de Ahones, condes de Sobradiel, t├¡tulo al que desde 1857 se sum├│ el de barones de Letosa (al a├▒o siguiente la casa fue reformada seg├║n proyecto del arquitecto Jos├® de Yarza Mi├▒ana), y desde 1898 el de condes de Gabarda. Desde 1930 este edificio es sede del Ilustre Colegio Notarial de Arag├│n. A la derecha de la imagen, posiblemente un autob├║s de la l├¡nea de la Almozara. Fuera de plano y desde 1962 estaba reubicada la fuente de La Samaritana. Fuente visual: fotograf├¡a de Guillermo Fat├ís Ojuel en Torralba, Federico; G├│mez de Valenzuela, Manuel, Cat├ílogo de monumentos hist├│ricos-art├¡sticos y edificios de inter├®s para el estudio del arte en la ciudad de Zaragoza. Cuadernos de Arag├│n n┬║ 73, IFC.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST├ôRICO', 41.65614600, -0.88190900, '0101000020E6100000BE8921399938ECBF5BB39597FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44913427611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44913427611.webp', 'https://www.flickr.com/photos/zaragozaantigua/44913427611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25918, 'Plaza del Mercado c.1900', 'Vista de la plaza del Mercado hacia 1900, con un tranv├¡a (posiblemente, un coche cerrado tipo C) tirado por caballer├¡a de la l├¡nea de Circunvalaci├│n (inaugurada en 1887 y electrificada en 1903). A la derecha, edificios que luego ser├ín derribados para la construcci├│n del Nuevo Mercado. Al fondo, calle de Antonio P├®rez.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST├ôRICO', 41.65651000, -0.88283500, '0101000020E61000000074982F2F40ECBF9CBF098508D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31251720050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31251720050.webp', 'https://www.flickr.com/photos/zaragozaantigua/31251720050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26037, 'Vista a├®rea centro 1957', 'Vista a├®rea del centro hist├│rico, con el Pilar y el Ebro a la izquierda. Destaca abajo el alargado Mercado Central. Fuente: TAF Helic├▓pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CASCO HIST├ôRICO', 41.65609900, -0.87968700, '0101000020E61000005BECF6596526ECBF1AF8510DFBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31213770422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31213770422.webp', 'https://www.flickr.com/photos/zaragozaantigua/31213770422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20870, 'La Seo rom├ínica', 'La catedral rom├ínica de La Seo hacia 1300, seg├║n J. A. P├®rez Casas sobre datos de B. Caba├▒ero. Fuente: Libro Historia de cuatro ciudades', 1308, 1118, 1499, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65445700, -0.87546200, '0101000020E61000000A815CE2C803ECBFB3D1393FC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978662856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978662856.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978662856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20873, 'Mezquita 1119', 'Probable aspecto de la mezquita de Sarakosta en 1119 un momento antes de su consagraci├│n como catedral, tras la conquista cristiana de la ciudad. En la imagen se han resaltado en color los muros que hoy est├ín visibles, tanto desde el exterior, como desde el interior del templo cat├│lico. Fuente: www.facebook.com/photo.php?fbid=996342230381622&set=p...', 1119, 1119, 1119, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15616159318.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15616159318.webp', 'https://www.flickr.com/photos/zaragozaantigua/15616159318/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20875, 'Cr├íneo de San Valero 1170', 'Pintura atribuida al zaragozano Bartolom├® Vicente, de comienzos del siglo XVIII, titulada "Llegada del cr├íneo de San Valero a Zaragoza procedente de Roda de Is├íbena", hoy en la capilla de San Valero en la catedral de San Salvador. Este cuadro recrea el retorno a la ciudad del cr├íneo del que fuera su obispo all├í por el siglo IV de la Era. Parece ser que, justo cuando estaba conform├índose el primitivo Reino de Arag├│n, varios siglos despu├®s de su muerte, alguien dio voces de que los restos de San Valero estaban all├í cerca de Anet (oeste de Par├¡s, Francia), aunque otras fuentes lo sit├║an en Enate (Barbastro). Se justific├│ el dislate geogr├ífico con el argumento de que eso era as├¡ porque habr├¡a sido all├¡ exiliado. En 1050, al poco de su "descubrimiento", lo que se identific├│ cient├¡ficamente como restos de su cuerpo fue llevado a la sede episcopal de Roda de Is├íbena, entonces cabeza eclesial del Reino de Arag├│n. Cuando las tropas de Alfonso I y de Gast├│n de Bearne conquistaron Sarakosta en 1118, se requiri├│ la presencia f├¡sica de las reliquias valerianas en la que fuera su sede episcopal ochocientos a├▒os antes. El cap├¡tulo de Roda acept├│ la cesi├│n y envi├│, primero un brazo y, en 1170, el cr├íneo del obispo, siendo ya rey el segundo Alfonso. Es lo que representa fielmente el cuadro, unos 530 a├▒os despu├®s de los hechos narrados, en composici├│n, abigarradas formas y parduzcos colores barrocos, y en un entorno zaragozano poco preciso, cerca de la Seo. El cr├íneo parece tener bastante buena cara, a pesar de todo. Fuente visual: "Vicente Berdus├ín (1632ÔÇô1697). El artista artesano", AA.VV., DPZ, 2006.', 1170, 1170, 1170, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18904769223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18904769223.webp', 'https://www.flickr.com/photos/zaragozaantigua/18904769223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20879, 'Zaragoza c.1400', 'Iluminaci├│n para manuscrito, 1350-1400. Representaci├│n idealizada de una batalla sin determinar frente a la puerta Norte de Zaragoza (luego del ├üngel) para ilustrar el relato de la historia de los romanos hasta la muerte de Julio C├®sar (44 antes de la Era). Como en otros dibujos similares (verbigracia los referentes al sitio de 542), la est├®tica corresponde a la ├®poca en que fueron realizados. Fuente: Les anciennes hystoires romaines, ca. 1350-1400, British Library, Londres.', 1400, 1400, 1400, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20027969505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20027969505.webp', 'https://www.flickr.com/photos/zaragozaantigua/20027969505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20880, 'Sello de Zaragoza 1299', 'Representaci├│n en un sello de cera municipal de la muralla medieval de Zaragoza, en un documento del Cabildo Metropolitano de 1299. La imagen del exterior de la ciudad con sus torreones es similar a la que aparece en esa ├®poca en otros municipios, por lo que se tratar├¡a de un alzado gen├®rico figurado, en todo caso cercano al aspecto de Zaragoza en el siglo XIII. En la parte superior, una cruz patriarcal, de doble travesa├▒o, que se├▒ala la urbe como sede arzobispal. Abajo, un le├│n rampante, blas├│n de Zaragoza. Fuente visual: Cat├ílogo "El municipio en Arag├│n", DPZ, 2004.', 1299, 1299, 1299, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20520454575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20520454575.webp', 'https://www.flickr.com/photos/zaragozaantigua/20520454575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20984, 'Pastos de Zaragoza 1803', '"Plano que manifiesta una porci├│n de terreno comprendido con las tres mojonaciones, las que incluyen las Yerbas o pastos para los ganados de esta Ilustr├¡sima ciudad de Zaragoza", Ambrosio Lanzaco, 1803. Se incluyen los terrenos comprendidos entre el sur de Pe├▒aflor (arriba) y los montes de Villamayor (abajo). A la izquierda, la Cartuja de Aula Dei y un tramo del r├¡o G├íllego. Fuente: AMZ.', 1803, 1803, 1803, 'Siglo XIX', NULL, 41.72954100, -0.79515100, '0101000020E6100000DB368C82E071E9BFAA0B789961DD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21034674276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21034674276.webp', 'https://www.flickr.com/photos/zaragozaantigua/21034674276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20881, 'Posesa en la Seo 1170', 'Banco del Retablo Mayor de la Seo de San Salvador (detalle). Pere Joan, Zaragoza, 1434-1440. Momento en el que un demonio en forma de drag├│n es expulsado por una mujer, en el interior de la Seo de Zaragoza. Al fondo, el busto-relicario de San Valero y, sobre la mesa del altar, el cr├íneo del obispo, a cuya intercesi├│n se atribuy├│ el milagro de la curaci├│n. Los cl├®rigos testigos del acontecimiento se agrupan a ambos lados del altar: uno de ellos, provisto de lentes, lee un libro de exorcismos, mientras los m├ís cercanos al diablo se tapan la nariz ante el hedor que desprende. Seg├║n Diego de Esp├®s, la escena se produjo en 1159; seg├║n Mart├¡n Carrillo, en 1170, coincidiendo con la traslaci├│n del cr├íneo de San Valero. El protagonista era un var├│n, pero el escultor le dio forma femenina, mezclando este suceso con el de una dama de la nobleza que tambi├®n se cur├│ de su posesi├│n en la Seo, seg├║n Carrillo, entrando a la fuerza "desnuda, con sola la camisa". Fuente: "Los posesos de Tosos", Mar├¡a Tausiet, Instituto Aragon├®s de Antropolog├¡a, 2002.', 1170, 1170, 1170, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65482800, -0.87568800, '0101000020E61000001EFD2FD7A205ECBFA7406667D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21558922942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21558922942.webp', 'https://www.flickr.com/photos/zaragozaantigua/21558922942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20884, 'La Seo 1397', 'Representaci├│n de F. Blanch que pretende ilustrar la medieval y ceremonial jura del nuevo rey de Arag├│n Mart├¡n I, tambi├®n llamado el Humano, y aun el Viejo, ante el justiciazgo Juan Jim├®nez Cerd├ín, en la catedral del Salvador de Zaragoza, iluminada para la ocasi├│n. Mientras, la viuda del difunto rey Juan I (Yolanda de Bar), y aun Mateo I (yerno del mismo), pugnaban tambi├®n por la sucesi├│n. Adem├ís, eran los tiempos del llamado "Cisma de Occidente", en el que un aragon├®s (Benedicto XIII) no solo era papa, sino que alcanz├│ el status de antipapa, respaldado fervorosa e interesadamente por el gerund├®s Mart├¡n I. Fuente visual: Historia de Espa├▒a, Miguel Segu├¡, 1910, en www.delcampe.es', 1397, 1397, 1397, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65472200, -0.87580700, '0101000020E6100000B073D3669C06ECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31616326644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31616326644.webp', 'https://www.flickr.com/photos/zaragozaantigua/31616326644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20904, 'Cabalgata universitaria 1588', 'Desarrollo de la cabalgata universitaria de 1588. Francisco Mel├®ndez. Boceto para aguafuerte, 1985. En 1583 se fund├│ la Universidad de Zaragoza. Cinco a├▒os despu├®s, el d├¡a de san Braulio (26 de marzo) de 1588, una cabalgata universitaria recorri├│ las calles de Zaragoza pasando por La Seo, como recoge el dibujo. Historia de Zaragoza', 1588, 1588, 1588, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65509500, -0.87546600, '0101000020E61000006551D845D103ECBFF6622827DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14835425239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14835425239.webp', 'https://www.flickr.com/photos/zaragozaantigua/14835425239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20914, 'Puerta del ├üngel 1564', 'Pintura de Antonio Mart├¡nez titulada "Arzobispo Hernando de Arag├│n, fundador de la Cartuja del Aula Dei, regresa con su s├®quito a la ciudad de Zaragoza". Este pintor posiblemente sea Jer├│nimo Mart├¡nez y Jenequi, hijo de Jusepe Mart├¡nez, que tras formarse en la pintura entr├│ como seglar en la cartuja de Aula Dei en 1665, donde pas├│ el resto de vida, hasta su muerte en 1690, sin abandonar su dedicaci├│n art├¡stica. Este cuadro, hoy en manos particulares, habr├¡a sido uno de los realizados durante su estancia cartujana, en composici├│n, dibujo, y t├®cnicas que beben claramente de las de su padre, considerado el pintor m├ís importante del siglo XVII en el antiguo Reino de Arag├│n. En el cuadro, el benefactor arzobispo aparece entre la Cartuja, ya terminada, a la izquierda, y la puerta del ├üngel de Zaragoza, a la derecha. Tras la puerta, la iglesia de San Juan del Puente, y las Casas de la Diputaci├│n. Fuente visual: "Territorium, el largo camino hacia las comarcas de Arag├│n", DGA, 2003.', 1564, 1564, 1564, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18936942313.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18936942313.webp', 'https://www.flickr.com/photos/zaragozaantigua/18936942313/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20921, 'Diputaci├│n del Reino 1756', '"Perfil de la Casa de la Audiencia de Zaragoza", 1756. Secci├│n de los edificios de la Diputaci├│n del Reino en la plaza de la Seo de Zaragoza, con visual de la Puerta del ├üngel desde el interior de la ciudad y la iglesia de San Juan del Puente, cuya torre con veleta era la oriental de la Puerta del ├üngel. Fuente: Archivo General Militar de Madrid. Ministerio de Defensa de Espa├▒a.', 1756, 1756, 1756, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65571800, -0.87593500, '0101000020E61000000F7F4DD6A807ECBF03B34291EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20022230512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20022230512.webp', 'https://www.flickr.com/photos/zaragozaantigua/20022230512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22814, 'Calle de la Divisi├│n Azul 1974', 'In├®dita imagen capturada en la calle de la Divisi├│n Azul y centrada en la moderna iglesia de San Jos├® Obrero construida a principios de los a├▒os 60 durante la segunda fase del Grupo de Viviendas "Jos├® Antonio Gir├│n" (por el nombre de este ministro de Trabajo) en el barrio de Las Fuentes, confrontando con el colegio de Santo Domingo de Silos. La singularidad de la fotograf├¡a reside en que, ante la total ausencia de los denominados en la ├®poca "clubs de ancianos" en este barrio de la periferia, muestra a algunos abuelos y abuelas que se congregaban en la fachada de esta iglesia porque su sure├▒a orientaci├│n la convirti├│ en una apreciada solanera donde aposentarse durante los meses de invierno para echar el rato. Actualmente, esta es la parroquia de San Jos├® Artesano, desde 1986 la calle se denomina de La Amistad, y desde 2009 este grupo de viviendas se conoce como Mar├¡a Andrea Casamayor (matem├ítica del siglo XVIII).', 1974, 1974, 1974, 'Anos 70', 'LAS FUENTES', 41.64726200, -0.86031300, '0101000020E6100000535BEA20AF87EBBFC6F8307BD9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51564621644.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51564621644.webp', 'https://www.flickr.com/photos/zaragozaantigua/51564621644/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22977, 'Audiorama 1991', 'Archivo Municipal. Carlos Gil Roig. "Terrenos del Audiorama". A finales de los a├▒os 70 del pasado siglo, la necesidad de un nuevo recinto ferial, m├ís amplio y espacioso, llev├│ a decidir el traslado de la Feria a una nueva ubicaci├│n. El Pleno de la C├ímara de Comercio e Industria decidi├│ que ser├¡a en la carretera de Madrid, frente a la Venta de los Caballos, coloc├índose la primera piedra el 10 de abril de 1983, e inaugur├índose en octubre de 1986. En la superficie del solar que se abandonaba se edificar├í el Auditorio-Palacio de Congresos de Zaragoza (inaugurado en octubre de 1994), la Sala Multiusos de Zaragoza, un espacio comercial, los cines Renoir-Audiorama, y la sede log├¡stica de la CAI. La C├ímara de Comercio se reservaba las edificaciones de la esquina Plaza Emperador Carlos-P┬║ Isabel la Cat├│lica, con la emblem├ítica torre-mirador que simbolizaba al conjunto. En la imagen, a├®rea visual del solar dejado por el derribo del recinto ferial, que desde 1986 y hasta 1990 hab├¡a sido utilizado en las Fiestas de octubre como sede de conciertos con la denominaci├│n de "Pabell├│n Franc├®s", por tener como escenario central un pabell├│n permanente Hispano-Franc├®s construido en 1958, en homenaje a la Expo 1908.', 1991, 1991, 1991, 'Anos 90', 'UNIVERSIDAD', 41.63770500, -0.90032000, '0101000020E61000003AE97DE36BCFECBF72BF4351A0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15619751322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15619751322.webp', 'https://www.flickr.com/photos/zaragozaantigua/15619751322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20926, 'Casas del Reino 1756', 'A mediados del siglo XV fue construido el Palacio de la Diputaci├│n del General del Reino de Arag├│n, Palacio de la Diputaci├│n, o "Casas del Reino", en un espacio de intensa concentraci├│n de poder institucional laico y religioso: la poderosa catedral del Salvador y el gran palacio Arzobispal (ocasional Residencia Real); la iglesia de San Juan del Puente, las Casas de la Ciudad, y el emergente complejo devocional de Nuestra Se├▒ora del Pilar. Inmediata quedaba la puerta de ingreso a la ciudad desde el puente de Piedras, que a├▒os despu├®s ser├¡a denominada "del ├üngel". Un siglo despu├®s, la Lonja de Mercaderes completar├¡a la densa trama pol├¡tico-institucional de este escogido espacio urbano. En las "Casas del Reino" estaba la Audiencia Real, el Justiciazgo, las Cortes, y la Diputaci├│n, adem├ís de Armer├¡a, Librer├¡a, Archivos, y Oratorio. La Nueva Planta administrativa del Reino de Arag├│n (abril de 1711), con la reorganizaci├│n de todos sus ├│rganos jur├¡dico-institucionales de gobierno, se realiz├│ sin afecciones a las Casas del Reino. En enero de 1809, durante el breve segundo Sitio franc├®s, este palacio result├│ muy afectado por el bombardeo, aunque parece ser que no fue reducido a literales "cenizas", con todo su rico patrimonio arquitect├│nico y art├¡stico, junto con los invaluables y preciosos documentos y legajos de todos sus archivos, como se ha venido repitiendo en la inmensa mayor├¡a de fuentes escritas despu├®s, para las que Zaragoza, tras 1809, qued├│ completamente arrasada. Seg├║n esa tradicional visi├│n, tras la graciosa cesi├│n de este Palacio al Arzobispado de Zaragoza en 1830, por Real Orden firmada por el rey Fernando VII, para levantar all├¡ el nuevo y necesario Seminario Conciliar de San Valero y San Braulio, los operarios constructores se habr├¡an encontrado con un solar quemado, arrasado, y ya casi preparado para cimientos. Parece ser que no fue exactamente as├¡. Sic transit gloria Urbis. En la imagen, plano de la planta calle de las Casas del Reino en 1756. El norte est', 1756, 1756, 1756, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65570500, -0.87596500, '0101000020E6100000B9196EC0E707ECBF6E693524EED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23995903013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23995903013.webp', 'https://www.flickr.com/photos/zaragozaantigua/23995903013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20937, 'Aparici├│n de la Virgen, s. XVI', '"Aparici├│n de la Virgen a Santiago Zebedeo en Zaragoza", tabla g├│tica flamenca, siglo XVI. En la vista figurada de la ciudad del fondo, aparece la Puerta del ├üngel. Fuente: eszaragoza.blogspot.com', 1550, 1500, 1599, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65614300, -0.87593500, '0101000020E61000000F7F4DD6A807ECBFEA3F6B7EFCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36718010784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36718010784.webp', 'https://www.flickr.com/photos/zaragozaantigua/36718010784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20945, 'Puerta del ├üngel 1813', 'Puerta de los Angelos. Edward Hawke Locker (dib.) y William Westall (lit.), 1824.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65592000, -0.87600000, '0101000020E6100000D578E9263108ECBF6B65C22FF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15002343922.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15002343922.webp', 'https://www.flickr.com/photos/zaragozaantigua/15002343922/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20959, 'Diputaci├│n del Reino 1831', 'Puerta del sal├│n de Cortes en el palacio de la Diputaci├│n del Reino de Zaragoza. Valent├¡n Carderera, entre 1831 y 1834. L├ípiz y aguada sobre papel. A la derecha, a l├ípiz: "Demolido". "La Diputaci├│n del General, conocida como Diputaci├│n del Reino, vigente entre 1364 y 1707, nace como organismo encargado de recaudar y administrar el dinero que en las Cortes Generales de Monz├│n de 1362 se hab├¡a ofrecido al monarca Pedro IV. Los acontecimientos pol├¡ticos ir├ín dotando a la instituci├│n de nuevas atribuciones, primero como ├│rgano rector de la hacienda real, despu├®s asumiendo la pol├¡tica del Reino en los periodos que separaban las reuniones de Cortes. Tambi├®n se ocup├│ de controlar la paz interna y externa, arbitrar las rivalidades surgidas entre nobles y universidades, defender los fueros y privilegios del reino, y controlar el Justiciazgo mediante la elecci├│n de sus lugartenientes. Tuvo su sede en un palacio situado en la Plaza de la Seo, conocido desde el siglo XV como ÔÇ£casas de la Diputaci├│nÔÇØ, espacio que comparti├│ con la Real Audiencia y la Gobernaci├│n General. A finales del siglo XV se produce una importante reforma en las instituciones aragonesas y la Diputaci├│n quedar├í bajo el control absoluto del monarca y, como consecuencia de las ÔÇ£alteraciones del ReinoÔÇØ, en las Cortes de Tarazona de 1592 ver├í reducidas sus atribuciones. La llegada de los Borbones supuso una nueva organizaci├│n del Reino y, a trav├®s de los Decretos de Nueva Planta dictados por Felipe V, las instituciones aragonesas quedaron disueltas, entre ellas la Diputaci├│n del Reino (1707)." M┬¬ Cruz Moreno Gajate. Archivo Diputaci├│n Provincial de Zaragoza. En la l├ímina, portada renacentista de la entrada a las Cortes, con un macero en el umbral. El edificio se termin├│ de construir en 1450 y sufri├│ da├▒os graves en 1809, siendo demolido en 1834. Fuente: "Viaje art├¡stico por Arag├│n de Valent├¡n Carderera", Jos├® Mar├¡a Lanzarote Guiral, e Itziar Arana Cobos, IFC - Fundaci├│n L├ízaro Galdiano, 2013.', 1831, 1831, 1831, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65550900, -0.87563500, '0101000020E6100000697407B13305ECBFE99D0AB8E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15360842572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15360842572.webp', 'https://www.flickr.com/photos/zaragozaantigua/15360842572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21121, 'La Seo 1889', 'Imagen tomada bajo el arco del Arzobispo en el arranque de la calle del Sepulcro y centrada en el lienzo norte de la Seo donde destaca en primer t├®rmino el denominado "muro de la Parroquieta" donde posa un abigarrado grupo de varones de diversas edades y condiciones sociales.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65494600, -0.87534400, '0101000020E61000008FFE976BD102ECBFB1524145D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31105192694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31105192694.webp', 'https://www.flickr.com/photos/zaragozaantigua/31105192694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21129, 'La Seo 1889', 'Imagen capturada desde cierta altura, posiblemente en el n┬║ 7 de la calle de la Lonja, y centrada en el neocl├ísico frontispicio y la barroca torre de la catedral de San Salvador o La Seo, recayentes a la hom├│nima plaza recientemente urbanizada. Entre el frontispicio y la torre, el cimborrio g├│tico-mud├®jar. A la izquierda, el palacio Arzobispal y el arco del Arzobispo, detr├ís del que emerge al fondo la torrecilla de la iglesia de San Nicol├ís de Bari.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65509100, -0.87599000, '0101000020E6100000F2EF332E1C08ECBFB4739A05DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41363224510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41363224510.webp', 'https://www.flickr.com/photos/zaragozaantigua/41363224510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21149, 'Ribera del Ebro c.1890', 'Paseo de la Ribera del Ebro. A la derecha, uno de los leones del puente de Piedra, el m├ís cercano al Pilar. Fuente: www.facebook.com/photo.php?fbid=10204473722256687&set...', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST├ôRICO', 41.65639400, -0.87574200, '0101000020E6100000EA7937161406ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15672875820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15672875820.webp', 'https://www.flickr.com/photos/zaragozaantigua/15672875820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
